const rawItems = $input.all();
const targets = [];
for (const raw of rawItems) {
  if (raw.json.list && Array.isArray(raw.json.list)) {
    for (const record of raw.json.list) {
      targets.push(record);
    }
  }
}
return [{ json: { count: targets.length, targets } }];

const f = $input.first().json;
const systemPrompt = '당신은 정부지원사업 행정 서류 작성 전문가입니다. 요청한 JSON 형식으로만 응답하세요.';
const userPrompt = `다음 정부지원사업에 신청하려고 합니다.

사업명: ${f['지원사업이름'] || ''}
주관기관: ${f['소관기관'] || ''}
카테고리: ${f['카테고리'] || '기타'}
지원 내용: ${f['적합이유'] || ''}
신청 난이도: ${f['신청난이도'] || '중'}
예상 지원규모: ${f['예상지원규모'] || '미상'}
예상 필요서류: ${f['필요서류_예측'] || ''}

[신청 기업 정보]
상호: Pressco21 (foreverlove.co.kr)
업종: 꽃/생활소품 온라인 도소매
규모: 소기업, 직원 8인
소재지: 서울 송파구

다음 두 가지를 JSON으로 반환해주세요:
1. required_docs: 필요 서류 목록 (배열)
2. business_plan_outline: 사업계획서 초안 항목 3가지 (각 100자 이내)

형식:{"required_docs": ["서류1", "서류2"], "business_plan_outline": ["항목1 내용", "항목2 내용", "항목3 내용"]}`;

return [{ json: {
  systemPrompt,
  userPrompt,
  _recordId: f['Id'] || 0,
  _bizName: f['지원사업이름'] || '',
  _agency: f['소관기관'] || '',
  _link: f['신청Link'] || '',
  _적합이유: f['적합이유'] || '',
  _핵심신청자격: f['핵심신청자격'] || '',
  _예상지원규모: f['예상지원규모'] || ''
} }];

const response = $input.first().json;
const promptData = $('Code 서류 프롬프트').item.json;

function extractText(resp) {
  if (resp.candidates?.[0]?.content?.parts?.[0]?.text) return resp.candidates[0].content.parts[0].text;
  if (resp.content?.parts?.[0]?.text) return resp.content.parts[0].text;
  if (resp.parts?.[0]?.text) return resp.parts[0].text;
  if (typeof resp.text === 'string') return resp.text;
  return '';
}

const text = extractText(response);
let requiredDocs = [];
let businessPlanOutline = [];

try {
  const codeBlock = text.match(/```json\s*([\s\S]*?)\s*```/i);
  let jsonStr = codeBlock ? codeBlock[1] : '';
  if (!jsonStr) { const obj = text.match(/\{[\s\S]*\}/); if (obj) jsonStr = obj[0]; }
  if (jsonStr) {
    const parsed = JSON.parse(jsonStr.trim());
    requiredDocs = parsed.required_docs || [];
    businessPlanOutline = parsed.business_plan_outline || [];
  }
} catch (e) {}

if (requiredDocs.length === 0) {
  requiredDocs = ['사업자등록증 사본', '법인등기부등본', '대표자 신분증 사본', '직전연도 재무제표', '4대보험 가입자명부'];
}

const docList = requiredDocs.map((d, i) => `${i+1}. ${d}`).join('\n');
const outlineList = businessPlanOutline.map((o, i) => `${i+1}. ${o}`).join('\n');
const linkText = promptData._link ? `\n\n🔗 <a href="${promptData._link}">공고 원문 보기</a>` : '';

const telegramText = `📋 <b>[행정서류 체크리스트]</b>\n${promptData._bizName}\n${promptData._agency}\n\n<b>📁 필요 서류</b>\n${docList}\n\n<b>📝 사업계획서 초안 방향</b>\n${outlineList || '내용 없음'}\n\n⚠️ <i>AI 생성 초안 — 담당자 검토/수정 필요</i>${linkText}`;

return [{ json: {
  _recordId: promptData._recordId,
  _bizName: promptData._bizName,
  _agency: promptData._agency,
  _link: promptData._link,
  _적합이유: promptData._적합이유,
  _핵심신청자격: promptData._핵심신청자격,
  _예상지원규모: promptData._예상지원규모,
  telegramText,
  docsCount: requiredDocs.length
} }];

const parsed = $('Code 서류 파싱').item.json;

const systemPrompt = '당신은 중소기업 정부지원사업 사업계획서 작성 전문가입니다. 요청한 JSON 형식으로만 응답하세요.';

const userPrompt = `다음 정부지원사업 신청용 사업계획서 초안을 작성해주세요.

지원사업: ${parsed._bizName}
주관기관: ${parsed._agency}
지원내용: ${parsed._적합이유 || ''}
핵심자격: ${parsed._핵심신청자격 || ''}
예상지원규모: ${parsed._예상지원규모 || ''}

[신청기업 정보]
- 상호: Pressco21 (foreverlove.co.kr)
- 업종: 꽃/생활소품 온라인 도소매
- 규모: 소기업, 직원 8인
- 소재지: 서울 송파구
- 주요현황: 자사몰 운영 + SNS마케팅 + 제휴강사플랫폼 운영

다음 JSON 형식으로만 응답하세요:
{"문서제목":"사업명 포함 제목","사업개요":"200자이내","현황분석":"200자이내","추진계획":"200자이내","기대효과":"200자이내","예산계획":"100자이내"}`;

return [{ json: {
  systemPrompt,
  userPrompt,
  _recordId: parsed._recordId,
  _bizName: parsed._bizName,
  _agency: parsed._agency,
  _link: parsed._link,
  _docsCount: parsed.docsCount || 0,
  _telegramText: parsed.telegramText
} }];

const response = $input.first().json;
const promptData = $('Code 사업계획서 프롬프트').item.json;

function extractText(resp) {
  if (resp.candidates?.[0]?.content?.parts?.[0]?.text) return resp.candidates[0].content.parts[0].text;
  if (resp.content?.parts?.[0]?.text) return resp.content.parts[0].text;
  if (resp.parts?.[0]?.text) return resp.parts[0].text;
  if (typeof resp.text === 'string') return resp.text;
  return '';
}

const text = extractText(response);

let plan = {
  문서제목: `${promptData._bizName} - 사업계획서 초안`,
  사업개요: '(생성 실패)',
  현황분석: '(생성 실패)',
  추진계획: '(생성 실패)',
  기대효과: '(생성 실패)',
  예산계획: '(생성 실패)'
};

try {
  const codeBlock = text.match(/```json\s*([\s\S]*?)\s*```/i);
  let jsonStr = codeBlock ? codeBlock[1] : '';
  if (!jsonStr) { const obj = text.match(/\{[\s\S]*\}/); if (obj) jsonStr = obj[0]; }
  if (jsonStr) {
    const parsed = JSON.parse(jsonStr.trim());
    plan = { ...plan, ...parsed };
  }
} catch (e) {}

const today = new Date().toISOString().slice(0, 10);

const fullContent = `${plan['문서제목']}\n작성일: ${today}  |  주관기관: ${promptData._agency}\n\n═══════════════════════════════════\n\n1. 사업 개요\n${plan['사업개요']}\n\n2. 현황 분석\n${plan['현황분석']}\n\n3. 추진 계획\n${plan['추진계획']}\n\n4. 기대 효과\n${plan['기대효과']}\n\n5. 예산 계획\n${plan['예산계획']}\n\n═══════════════════════════════════\n⚠ AI 생성 초안 — 담당자 검토 및 수정 필요\n신청 링크: ${promptData._link || '미제공'}\n`;

return [{ json: {
  _recordId: promptData._recordId,
  _bizName: promptData._bizName,
  _agency: promptData._agency,
  _link: promptData._link,
  _telegramText: promptData._telegramText,
  docTitle: plan['문서제목'],
  fullContent,
  today
} }];

